  "main": "index.js",
  "hooks": ["message_sending"],
  "configSchema": {
    "type": "object",
    "properties": {
      "thresholdPercent": { "type": "number", "default": 80 },
      "autoCompactPercent": { "type": "number", "default": 90 },
      "autoCompactEnabled": { "type": "boolean", "default": true },
      "warningPrefix": { "type": "string", "default": "⚠️ **上下文使用已达 {percent}%**" },
      "showCompactHint": { "type": "boolean", "default": true },
      "showNewHint": { "type": "boolean", "default": true },
      "minIntervalMs": { "type": "number", "default": 60000 },
